SELECT count(*) FROM name, cast_info, char_name, role_type, aka_name, title, movie_info WHERE cast_info.person_id = name.id AND cast_info.person_role_id = char_name.id AND cast_info.role_id = role_type.id AND aka_name.person_id = name.id AND cast_info.movie_id = title.id AND movie_info.movie_id = title.id;